// Tokyo Night August Aurora — floating ember islands
{
  "layer": "top",
  "position": "top",
  "height": 34,
  "spacing": 0,
  "margin-top": 8,
  "margin-left": 14,
  "margin-right": 14,
  "modules-left": ["custom/launcher", "hyprland/workspaces", "hyprland/window"],
  "modules-center": ["clock"],
  "modules-right": ["tray", "pulseaudio", "network", "cpu", "memory", "battery", "custom/power"],

  "custom/launcher": { "format": "󰣇", "on-click": "wofi --show drun", "tooltip": false },
  "hyprland/workspaces": {
    "format": "{id}",
    "on-click": "activate",
    "persistent-workspaces": { "*": 5 }
  },
  "hyprland/window": { "format": "  {title}", "max-length": 45, "separate-outputs": true },
  "clock": {
    "format": "  {:%H:%M   %a %d %b}",
    "tooltip-format": "<tt><big>{calendar}</big></tt>"
  },
  "cpu": { "format": "  {usage}%", "interval": 2 },
  "memory": { "format": "  {percentage}%" },
  "network": {
    "format-wifi": "  {essid}",
    "format-ethernet": "  wired",
    "format-disconnected": "󰤭  off",
    "tooltip-format": "{ifname}  {ipaddr}"
  },
  "pulseaudio": {
    "format": "{icon}  {volume}%",
    "format-muted": "  muted",
    "format-icons": { "default": ["", "", ""] },
    "on-click": "pavucontrol"
  },
  "battery": {
    "format": "{icon}  {capacity}%",
    "format-charging": "  {capacity}%",
    "format-icons": ["", "", "", "", ""],
    "states": { "warning": 30, "critical": 15 }
  },
  "tray": { "spacing": 10 },
  "custom/power": { "format": "󰐥", "on-click": "hyprlock", "tooltip": false }
}

/* Tokyo Night August Aurora */
* {
  font-family: "JetBrainsMono Nerd Font", monospace;
  font-size: 13px;
  font-weight: bold;
  min-height: 0;
}
window#waybar { background: transparent; }

#custom-launcher, #workspaces, #window, #clock, #tray,
#pulseaudio, #network, #cpu, #memory, #battery, #custom-power {
  background: alpha(#1b1412, 0.84);
  border: 1px solid alpha({{accent}}, 0.22);
  border-radius: 14px;
  padding: 1px 12px;
  margin: 3px 3px;
  box-shadow: 0 2px 8px alpha(#160b08, 0.50);
}

#custom-launcher {
  color: {{accent}};
  font-size: 18px;
  padding: 0 14px;
  margin-left: 4px;
}
#custom-launcher:hover { color: #ffc061; }

#workspaces { padding: 1px 6px; }
#workspaces button {
  color: #6f5148;
  padding: 0 6px;
  margin: 0 1px;
  border-radius: 10px;
  transition: all 0.25s cubic-bezier(0.55, 0, 0.28, 1.68);
}
#workspaces button.active {
  color: #1b1412;
  background: linear-gradient(45deg, {{ember}}, {{accent}}, #ffc061);
  box-shadow: 0 0 12px alpha(#ff7a5c, 0.55);
  padding: 0 12px;
}
#workspaces button:hover {
  color: #f4d6bf;
  background: alpha(#ff7a5c, 0.20);
  box-shadow: none;
}

#window { color: #ddb6a2; }
#clock { color: #ffc061; }
#cpu { color: #f6c177; }
#memory { color: {{accent}}; }
#network { color: #ff7a5c; }
#pulseaudio { color: {{ember}}; }
#pulseaudio.muted { color: #6f5148; }
#battery { color: #f6c177; }
#battery.warning { color: {{accent}}; }
#battery.critical { color: {{ember}}; }
#custom-power { color: {{ember}}; font-size: 15px; padding: 0 13px; margin-right: 4px; }
#custom-power:hover { color: #ffc061; }
#tray { padding: 1px 10px; }
tooltip {
  background: #1b1412;
  border: 1px solid {{accent}};
  border-radius: 12px;
}
tooltip label { color: #f4d6bf; }

/* Tokyo Night August launcher */
window {
  margin: 0;
  background: alpha(#1b1412, 0.80);
  border: 2px solid {{accent}};
  border-radius: 20px;
  font-family: "JetBrainsMono Nerd Font";
}
#input {
  margin: 14px;
  padding: 12px 16px;
  color: #f4d6bf;
  background: alpha(#3a2520, 0.9);
  border: none;
  border-radius: 14px;
  font-size: 15px;
}
#inner-box { margin: 6px 14px 14px 14px; }
#entry {
  padding: 8px 12px;
  margin: 2px 0;
  border-radius: 12px;
}
#entry:selected {
  background: linear-gradient(45deg, alpha({{ember}}, 0.9), alpha({{accent}}, 0.9), alpha(#ffc061, 0.9));
}
#entry:selected #text { color: #1b1412; }
#text { color: #f4d6bf; margin-left: 8px; }
#img { margin-right: 6px; }
